const Rating = ({ value, text }) => {
  return (
    <div className="rating" aria-label={`Ocena ${value}`}>
      {[1, 2, 3, 4, 5].map((star) => (
        <span key={star}>{value >= star ? '*' : value >= star - 0.5 ? '*' : '-'}</span>
      ))}
      {text && <span className="rating-text">{text}</span>}
    </div>
  );
};

export default Rating;
